$ErrorActionPreference = "Stop"

# ============================================================
# CONFIG
# ============================================================

$MainDir            = "C:\Windows\System32\Acceleron\"
$BaseDir            = Join-Path $MainDir "Wallpaper"
$CertDir            = Join-Path $MainDir "Certificate"

$PolicyExePath      = Join-Path $BaseDir "WallpaperPolicy.exe"
$UpdateExePath      = Join-Path $BaseDir "WallpaperUpdate.exe"
$CertPath           = Join-Path $CertDir "GainwellWallpaper.cer"

$PolicyTaskName     = "Wallpaper Policy"
$UpdateTaskName     = "Wallpaper Update Schedule"

$PinnedThumbprint   = "ECACA66CD84B620E80C8329A253DE85149666D6E"

$TriggerInterval    = 5
$IsSystem           = ([Security.Principal.WindowsIdentity]::GetCurrent().IsSystem)
$IsAdmin            = ([Security.Principal.WindowsPrincipal] `
                      [Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)

# ============================================================
# ENSURE BASE DIRECTORY
# ============================================================

# Create base directory if not exists
if (-not (Test-Path $BaseDir)) {
    New-Item -Path $BaseDir -ItemType Directory -Force | Out-Null
}

# Create certificate directory if not exists
if (-not (Test-Path $CertDir)) {
    New-Item -Path $CertDir -ItemType Directory -Force | Out-Null
}

# ============================================================
# CLEAN OLD TASKS (SAFE)
# ============================================================

# Kill running wallpaper processes if active
Get-Process -Name "WallpaperWatcher" -ErrorAction SilentlyContinue | Stop-Process -Force
Get-Process -Name "WallpaperUpdate"  -ErrorAction SilentlyContinue | Stop-Process -Force

# Remove scheduled tasks
Get-ScheduledTask $PolicyTaskName -ErrorAction SilentlyContinue | Unregister-ScheduledTask -Confirm:$false
Get-ScheduledTask $UpdateTaskName -ErrorAction SilentlyContinue | Unregister-ScheduledTask -Confirm:$false

# Remove old helper files
Remove-Item "C:\Windows\System32\WallpaperPolicy.vbs" -Force -ErrorAction SilentlyContinue
Remove-Item "C:\Windows\System32\SetWallpaper.vbs" -Force -ErrorAction SilentlyContinue
Remove-Item "C:\ProgramData\Acceleron" -Force -Recurse -ErrorAction SilentlyContinue
Remove-Item "$BaseDir\*" -Force -Recurse -ErrorAction SilentlyContinue

# ============================================================
# EMBEDDED BINARIES (BASE64)
# ============================================================

$CertBase64 = @'

'@

$WallpaperPolicyExeBase64 = @'

'@

$WallpaperUpdateExeBase64 = @'

'@

# ============================================================
# DECODE EXEs
# ============================================================

$PolicyExeBytes = [Convert]::FromBase64String($WallpaperPolicyExeBase64)
$UpdateExeBytes = [Convert]::FromBase64String($WallpaperUpdateExeBase64)

# ============================================================
# WRITE + TRUST CERTIFICATE (SYSTEM ONLY)
# ============================================================

if ($IsSystem -or $IsAdmin) {

    if (-not (Test-Path $CertPath)) {
        [IO.File]::WriteAllBytes(
            $CertPath,
            [Convert]::FromBase64String($CertBase64)
        )
    }

    foreach ($store in @(
        "Root",
        "TrustedPublisher"
    )) {
        if (-not (certutil -store $store | Select-String $PinnedThumbprint)) {
            & certutil.exe -addstore $store $CertPath | Out-Null
        }
    }
}

# ============================================================
# WRITE POLICY SCRIPT (SYSTEM)
# ============================================================
$WritePolicyExe = $true

if (Test-Path $PolicyExePath) {

    $Sig = Get-AuthenticodeSignature $PolicyExePath

    if (
        $Sig.SignerCertificate -and
        $Sig.SignerCertificate.Thumbprint -eq $PinnedThumbprint
    ) {
        $WritePolicyExe = $false
    }
}

if ($WritePolicyExe) {

    [IO.File]::WriteAllBytes($PolicyExePath, $PolicyExeBytes)

    Start-Sleep 2
    $Sig = Get-AuthenticodeSignature $PolicyExePath

    if (
        -not $Sig.SignerCertificate -or
        $Sig.SignerCertificate.Thumbprint -ne $PinnedThumbprint -or
        $Sig.Status -in @('HashMismatch','NotSigned')
    ) {
        throw "WallpaperPolicy.exe signature validation failed"
    }
}

# ============================================================
# WRITE UPDATE SCRIPT (USER / SYSTEM DUAL MODE)
# ============================================================

$WriteUpdateExe = $true

if (Test-Path $UpdateExePath) {

    $Sig = Get-AuthenticodeSignature $UpdateExePath

    if (
        $Sig.SignerCertificate -and
        $Sig.SignerCertificate.Thumbprint -eq $PinnedThumbprint
    ) {
        $WriteUpdateExe = $false
    }
}

if ($WriteUpdateExe) {

    [IO.File]::WriteAllBytes($UpdateExePath, $UpdateExeBytes)

    Start-Sleep 2
    $Sig = Get-AuthenticodeSignature $UpdateExePath

    if (
        -not $Sig.SignerCertificate -or
        $Sig.SignerCertificate.Thumbprint -ne $PinnedThumbprint -or
        $Sig.Status -in @('HashMismatch','NotSigned')
    ) {
        throw "WallpaperUpdate.exe signature validation failed"
    }
}

# ============================================================
# SCHEDULED TASK: POLICY (SYSTEM)
# ============================================================

# Generate correct timestamp
$startTime = (Get-Date).AddMinutes(1).ToString("yyyy-MM-ddTHH:mm:ss")

$tempXml = "$env:TEMP\WallpaperPolicy.xml"

# ---------------- CREATE XML ----------------
$xml = @"
<?xml version="1.0" encoding="UTF-16"?>
<Task version="1.3" xmlns="http://schemas.microsoft.com/windows/2004/02/mit/task">
  <RegistrationInfo>
    <Author>Acceleron</Author>
    <URI>\Wallpaper Policy</URI>
  </RegistrationInfo>
  <Triggers>
    <TimeTrigger>
      <StartBoundary>$startTime</StartBoundary>
      <Enabled>true</Enabled>
    </TimeTrigger>
    <LogonTrigger>
      <Enabled>true</Enabled>
    </LogonTrigger>
    <SessionStateChangeTrigger>
      <Enabled>true</Enabled>
      <StateChange>SessionUnlock</StateChange>
    </SessionStateChangeTrigger>
  </Triggers>
  <Principals>
    <Principal id="Author">
      <UserId>S-1-5-18</UserId>
      <RunLevel>HighestAvailable</RunLevel>
    </Principal>
  </Principals>
  <Settings>
    <MultipleInstancesPolicy>IgnoreNew</MultipleInstancesPolicy>
    <DisallowStartIfOnBatteries>false</DisallowStartIfOnBatteries>
    <StopIfGoingOnBatteries>false</StopIfGoingOnBatteries>
    <AllowHardTerminate>true</AllowHardTerminate>
    <StartWhenAvailable>true</StartWhenAvailable>
    <RunOnlyIfNetworkAvailable>false</RunOnlyIfNetworkAvailable>
    <IdleSettings>
      <StopOnIdleEnd>true</StopOnIdleEnd>
      <RestartOnIdle>false</RestartOnIdle>
    </IdleSettings>
    <AllowStartOnDemand>true</AllowStartOnDemand>
    <Enabled>true</Enabled>
    <Hidden>true</Hidden>
    <RunOnlyIfIdle>false</RunOnlyIfIdle>
    <DisallowStartOnRemoteAppSession>false</DisallowStartOnRemoteAppSession>
    <UseUnifiedSchedulingEngine>true</UseUnifiedSchedulingEngine>
    <WakeToRun>true</WakeToRun>
    <ExecutionTimeLimit>PT0S</ExecutionTimeLimit>
    <Priority>7</Priority>
  </Settings>
  <Actions Context="Author">
    <Exec>
      <Command>$PolicyExePath</Command>
    </Exec>
  </Actions>
</Task>
"@

# Save XML
$xml | Out-File -FilePath $tempXml -Encoding UTF32

# ---------------- REGISTER TASK ----------------
$null = Register-ScheduledTask -TaskName $PolicyTaskName -Xml (Get-Content $tempXml | Out-String) -Force

# ============================================================
# SCHEDULED TASK: WALLPAPER UPDATE (USER, NO POPUP)
# ============================================================

$tempXml = "$env:TEMP\WallpaperUpdate.xml"

# ---------------- CREATE XML ----------------
$xml = @"
<?xml version="1.0" encoding="UTF-16"?>
<Task version="1.3" xmlns="http://schemas.microsoft.com/windows/2004/02/mit/task">
  <RegistrationInfo>
    <Author>Acceleron</Author>
    <URI>\Wallpaper Update Schedule</URI>
  </RegistrationInfo>
  <Triggers>
    <TimeTrigger>
      <StartBoundary>$startTime</StartBoundary>
      <Enabled>true</Enabled>
    </TimeTrigger>
    <LogonTrigger>
      <Enabled>true</Enabled>
    </LogonTrigger>
    <SessionStateChangeTrigger>
      <Enabled>true</Enabled>
      <StateChange>SessionUnlock</StateChange>
    </SessionStateChangeTrigger>
    <SessionStateChangeTrigger>
      <Enabled>true</Enabled>
      <StateChange>ConsoleConnect</StateChange>
    </SessionStateChangeTrigger>
  </Triggers>
  <Principals>
    <Principal id="Author">
      <GroupId>S-1-5-4</GroupId>
      <RunLevel>HighestAvailable</RunLevel>
    </Principal>
  </Principals>
  <Settings>
    <MultipleInstancesPolicy>IgnoreNew</MultipleInstancesPolicy>
    <DisallowStartIfOnBatteries>false</DisallowStartIfOnBatteries>
    <StopIfGoingOnBatteries>false</StopIfGoingOnBatteries>
    <AllowHardTerminate>true</AllowHardTerminate>
    <StartWhenAvailable>true</StartWhenAvailable>
    <RunOnlyIfNetworkAvailable>false</RunOnlyIfNetworkAvailable>
    <IdleSettings>
      <StopOnIdleEnd>true</StopOnIdleEnd>
      <RestartOnIdle>false</RestartOnIdle>
    </IdleSettings>
    <AllowStartOnDemand>true</AllowStartOnDemand>
    <Enabled>true</Enabled>
    <Hidden>true</Hidden>
    <RunOnlyIfIdle>false</RunOnlyIfIdle>
    <DisallowStartOnRemoteAppSession>false</DisallowStartOnRemoteAppSession>
    <UseUnifiedSchedulingEngine>true</UseUnifiedSchedulingEngine>
    <WakeToRun>true</WakeToRun>
    <ExecutionTimeLimit>PT0S</ExecutionTimeLimit>
    <Priority>7</Priority>
  </Settings>
  <Actions Context="Author">
    <Exec>
      <Command>$UpdateExePath</Command>
    </Exec>
  </Actions>
</Task>
"@

# Save XML
$xml | Out-File -FilePath $tempXml -Encoding UTF32

# ---------------- REGISTER TASK ----------------
$null = Register-ScheduledTask -TaskName $UpdateTaskName -Xml (Get-Content $tempXml | Out-String) -Force

# ---------------- CLEANUP ----------------
Remove-Item $tempXml -Force -ErrorAction SilentlyContinue

Write-Host "Wallpaper Policy Updated"